module RefModule (
    input wire a,
    input wire b,
    output wire hazard_detected,
    output wire resolved
);
    wire __hazard_detected_tmp = a & b;
    assign hazard_detected = __hazard_detected_tmp; // Hazard detected if both inputs are 1
    assign resolved = ~(a & b); // Hazard resolved if at least one input is 0
endmodule
